import{E as e}from"./index-YJU_NjKJ.js";const u={register(r){return e.post("/user/register",r)},login(r){return e.post("/user/login",r)},getMe(){return e.get("/user/me")},refresh(r){return e.post("/user/refresh",r)},logout(){return e.post("/user/logout")},update(r,t){return e.put(`/user/${r}`,t)},uploadAvatar(r,t){return e.put(`/user/${r}/avatar`,t)},changePassword(r,t){return e.put(`/user/${r}/password`,t)},getPublicProfile(r){return e.get(`/user/${r}`)},getSolvedProblems(r,t){return e.get(`/user/${r}/solved`,{params:t})},getUserProblems(r,t){return e.get(`/user/${r}/problems`,{params:t})}};export{u};
